     1→import { writeFileSync } from 'node:fs';
     2→import { resolve } from 'node:path';
     3→import type { CheckpointMeta, CheckpointsCache, TurnMeta } from './types.js';
     4→
     5→const REPO = 'ShamsiievDmytro/entire-bmad';
     6→const BRANCH = 'entire/checkpoints/v1';
     7→const BRANCH_ENCODED = encodeURIComponent(BRANCH);
     8→const BASE_URL = 'https://api.github.com';
     9→const RETRY_DELAY_MS = 2000;
    10→const PROMPT_TXT_MAX_LEN = 200;
    11→
    12→let apiCallCount = 0;
    13→
    14→export function buildHeaders(token?: string): Record<string, string> {
    15→  const headers: Record<string, string> = {
    16→    'User-Agent': 'metrics-fetch-script',
    17→    Accept: 'application/vnd.github+json',
    18→  };
    19→  if (token) {
    20→    headers['Authorization'] = `Bearer ${token}`;
    21→  }
    22→  return headers;
    23→}
    24→
    25→export function extractBmadCommands(jsonlContent: string): Record<string, number> {
    26→  const counts: Record<string, number> = {};
    27→  const commandRegex = /^\/[a-z][a-z0-9-]*/;
    28→
    29→  for (const line of jsonlContent.split('\n')) {
    30→    if (!line.trim()) continue;
    31→    let parsed: unknown;
    32→    try {
    33→      parsed = JSON.parse(line);
    34→    } catch {
    35→      continue;
    36→    }
    37→    if (!isRecord(parsed) || parsed['type'] !== 'user') continue;
    38→
    39→    const content = getString(parsed, 'content') ?? getString(parsed, 'prompt') ?? '';
    40→    const trimmed = content.trimStart();
    41→    const match = commandRegex.exec(trimmed);
    42→    if (match) {
    43→      const cmd = match[0];
    44→      counts[cmd] = (counts[cmd] ?? 0) + 1;
    45→    }
    46→  }
    47→  return counts;
    48→}
    49→
    50→async function sleep(ms: number): Promise<void> {
    51→  return new Promise((resolve) => setTimeout(resolve, ms));
    52→}
    53→
    54→export async function fetchWithRetry(
    55→  url: string,
    56→  headers: Record<string, string>,
    57→  delayFn: (ms: number) => Promise<void> = sleep
    58→): Promise<unknown> {
    59→  apiCallCount++;
    60→  let lastError: Error | null = null;
    61→
    62→  for (let attempt = 0; attempt < 2; attempt++) {
    63→    if (attempt > 0) await delayFn(RETRY_DELAY_MS);
    64→    try {
    65→      const res = await fetch(url, { headers });
    66→      if (!res.ok) {
    67→        throw new Error(`HTTP ${res.status} for ${url}`);
    68→      }
    69→      return await res.json();
    70→    } catch (err) {
    71→      lastError = err instanceof Error ? err : new Error(String(err));
    72→    }
    73→  }
    74→  throw lastError ?? new Error(`Failed to fetch ${url}`);
    75→}
    76→
    77→async function fetchContent(
    78→  path: string,
    79→  headers: Record<string, string>
    80→): Promise<string> {
    81→  const url = `${BASE_URL}/repos/${REPO}/contents/${path}?ref=${BRANCH_ENCODED}`;
    82→  const data = await fetchWithRetry(url, headers);
    83→  if (!isRecord(data) || typeof data['content'] !== 'string') {
    84→    throw new Error(`Unexpected contents response for ${path}`);
    85→  }
    86→  return Buffer.from(data['content'].replace(/[\r\n]/g, ''), 'base64').toString('utf-8');
    87→}
    88→
    89→function isRecord(val: unknown): val is Record<string, unknown> {
    90→  return typeof val === 'object' && val !== null && !Array.isArray(val);
    91→}
    92→
    93→function getNumber(obj: Record<string, unknown>, key: string): number {
    94→  const v = obj[key];
    95→  return typeof v === 'number' ? v : 0;
    96→}
    97→
    98→function getString(obj: Record<string, unknown>, key: string): string | undefined {
    99→  const v = obj[key];
   100→  return typeof v === 'string' ? v : undefined;
   101→}
   102→
   103→function getArray(obj: Record<string, unknown>, key: string): unknown[] {
   104→  const v = obj[key];
   105→  return Array.isArray(v) ? v : [];
   106→}
   107→
   108→function countOrLength(obj: Record<string, unknown>, key: string): number {
   109→  const v = obj[key];
   110→  if (typeof v === 'number') return v;
   111→  if (Array.isArray(v)) return v.length;
   112→  return 0;
   113→}
   114→
   115→function parseTurn(raw: Record<string, unknown>): TurnMeta {
   116→  const promptRaw = getString(raw, 'prompt_txt') ?? getString(raw, 'prompt') ?? '';
   117→  const prompt_txt = promptRaw.split('\n')[0]?.slice(0, PROMPT_TXT_MAX_LEN) ?? '';
   118→  return {
   119→    turn_id: getString(raw, 'turn_id') ?? getString(raw, 'id') ?? '',
   120→    session_id: getString(raw, 'session_id') ?? '',
   121→    model: getString(raw, 'model') ?? '',
   122→    prompt_txt,
   123→    turn_count: getNumber(raw, 'turn_count'),
   124→    agent_percentage: getNumber(raw, 'agent_percentage'),
   125→  };
   126→}
   127→
   128→export function parseMetadata(
   129→  raw: unknown,
   130→  checkpointId: string,
   131→  commitDate: string
   132→): Omit<CheckpointMeta, 'bmad_commands' | 'fetch_failed'> {
   133→  if (!isRecord(raw)) {
   134→    return {
   135→      checkpoint_id: checkpointId,
   136→      commit_date: commitDate,
   137→      agent_percentage: 0,
   138→      agent_lines: 0,
   139→      human_added: 0,
   140→      human_modified: 0,
   141→      human_removed: 0,
   142→      tokens: { input: 0, cache_creation: 0, cache_read: 0, output: 0 },
   143→      summary: { friction: [], open_items: [] },
   144→      learnings: { repo: 0, code: 0, workflow: 0 },
   145→      files_touched: [],
   146→      turns: [],
   147→    };
   148→  }
   149→
   150→  const hasNestedTokens = isRecord(raw['tokens']);
   151→  const tokensRaw = hasNestedTokens ? raw['tokens'] : {};
   152→  const tokens = {
   153→    input: hasNestedTokens ? getNumber(tokensRaw, 'input') : getNumber(raw, 'input_tokens'),
   154→    cache_creation: hasNestedTokens ? getNumber(tokensRaw, 'cache_creation') : getNumber(raw, 'cache_creation_tokens'),
   155→    cache_read: hasNestedTokens ? getNumber(tokensRaw, 'cache_read') : getNumber(raw, 'cache_read_tokens'),
   156→    output: hasNestedTokens ? getNumber(tokensRaw, 'output') : getNumber(raw, 'output_tokens'),
   157→  };
   158→
   159→  const summaryRaw = isRecord(raw['summary']) ? raw['summary'] : {};
   160→  const frictionRaw = getArray(summaryRaw, 'friction');
   161→  const openItemsRaw = getArray(summaryRaw, 'open_items');
   162→  const summary = {
   163→    friction: frictionRaw.filter((x): x is string => typeof x === 'string'),
   164→    open_items: openItemsRaw.filter((x): x is string => typeof x === 'string'),
   165→  };
   166→
   167→  const learningsRaw = isRecord(raw['learnings']) ? raw['learnings'] : {};
   168→  const learnings = {
   169→    repo: countOrLength(learningsRaw, 'repo'),
   170→    code: countOrLength(learningsRaw, 'code'),
   171→    workflow: countOrLength(learningsRaw, 'workflow'),
   172→  };
   173→
   174→  const filesTouchedRaw = getArray(raw, 'files_touched');
   175→  const files_touched = filesTouchedRaw.filter((x): x is string => typeof x === 'string');
   176→
   177→  const turnsRaw = getArray(raw, 'turns');
   178→  const turns = turnsRaw.filter((t): t is Record<string, unknown> => isRecord(t)).map(parseTurn);
   179→
   180→  return {
   181→    checkpoint_id: getString(raw, 'checkpoint_id') ?? checkpointId,
   182→    commit_date: commitDate,
   183→    agent_percentage: getNumber(raw, 'agent_percentage'),
   184→    agent_lines: getNumber(raw, 'agent_lines'),
   185→    human_added: getNumber(raw, 'human_added'),
   186→    human_modified: getNumber(raw, 'human_modified'),
   187→    human_removed: getNumber(raw, 'human_removed'),
   188→    tokens,
   189→    summary,
   190→    learnings,
   191→    files_touched,
   192→    turns,
   193→  };
   194→}
   195→
   196→async function fetchAllCommits(headers: Record<string, string>): Promise<unknown[]> {
   197→  const all: unknown[] = [];
   198→  let page = 1;
   199→  while (true) {
   200→    const url = `${BASE_URL}/repos/${REPO}/commits?sha=${BRANCH_ENCODED}&per_page=100&page=${page}`;
   201→    const data = await fetchWithRetry(url, headers);
   202→    if (!Array.isArray(data) || data.length === 0) break;
   203→    all.push(...data);
   204→    if (data.length < 100) break;
   205→    page++;
   206→  }
   207→  return all;
   208→}
   209→
   210→async function run(): Promise<void> {
   211→  apiCallCount = 0;
   212→  const startTime = Date.now();
   213→  const token = process.env['GITHUB_TOKEN'];
   214→  const headers = buildHeaders(token);
   215→
   216→  if (!token) {
   217→    console.warn('WARN: No GITHUB_TOKEN set — unauthenticated requests (60 req/hour limit)');
   218→  }
   219→
   220→  // Step 1: Discover checkpoints via tree API
   221→  console.log('Step 1: Discovering checkpoints...');
   222→  const treeUrl = `${BASE_URL}/repos/${REPO}/git/trees/${BRANCH_ENCODED}?recursive=1`;
   223→  const treeData = await fetchWithRetry(treeUrl, headers);
   224→  if (!isRecord(treeData) || !Array.isArray(treeData['tree'])) {
   225→    throw new Error('Unexpected tree API response');
   226→  }
   227→  if (treeData['truncated'] === true) {
   228→    console.warn('WARN: GitHub tree response is truncated — some checkpoints may be missing');
   229→  }
   230→
   231→  const metadataPaths: Array<{ id: string; path: string }> = [];
   232→  for (const item of treeData['tree']) {
   233→    if (!isRecord(item) || typeof item['path'] !== 'string') continue;
   234→    const match = /^checkpoints\/([^/]+)\/metadata\.json$/.exec(item['path']);
   235→    if (match) {
   236→      metadataPaths.push({ id: match[1], path: item['path'] });
   237→    }
   238→  }
   239→  console.log(`  Found ${metadataPaths.length} checkpoints`);
   240→
