() => {
  const results = {};
  // Meta bar
  results.repo = document.querySelector('p.text-accent-primary')?.textContent?.trim();
  results.checkpointCount = [...document.querySelectorAll('p.font-semibold')].find(p => p.textContent?.trim() === '5')?.textContent;
  // Attribution stats
  results.pureAiRate = document.querySelector('[style*="font-size:48px"]')?.textContent?.trim();
  results.zeroHumanLines = [...document.querySelectorAll('[style*="font-size:48px"]')][1]?.textContent?.trim();
  // All section headings h2
  results.sectionHeadings = [...document.querySelectorAll('h2')].map(h => h.textContent?.trim());
  // All metric headings h3
  results.metricHeadings = [...document.querySelectorAll('h3')].map(h => h.textContent?.trim());
  // Canvases rendered
  results.canvasIds = [...document.querySelectorAll('canvas')].map(c => c.id);
  // lightweight-charts containers
  results.lwcContainers = [...document.querySelectorAll('[id^="metric-"]')].filter(el => el.tagName === 'DIV').map(el => el.id);
  return results;
}

() => {
  const results = {};

  // Check lightweight-charts containers have canvas children (rendered)
  const lwcIds = ['metric-1', 'metric-7', 'metric-11', 'metric-20'];
  results.lwcRendered = lwcIds.map(id => {
    const el = document.getElementById(id);
    return { id, hasCanvas: !!el?.querySelector('canvas'), hasChild: !!el?.firstChild };
  });

  // Check Chart.js canvases have a non-zero size context
  const canvasIds = ['metric-3', 'metric-4', 'metric-6', 'metric-8', 'metric-9',
    'metric-10', 'metric-12', 'metric-13', 'metric-14', 'metric-15', 'metric-16',
    'metric-17', 'metric-18', 'metric-19'];
  results.chartjsRendered = canvasIds.map(id => {
    const el = document.getElementById(id) as HTMLCanvasElement;
    return { id, width: el?.width, height: el?.height };
  });

  // Check if any "No data available" messages appear
  const noDataTexts = [...document.querySelectorAll('div')].filter(
    d => d.textContent?.trim() === 'No data available'
  );
  results.noDataCount = noDataTexts.length;

  return results;
}

function() {
  var lwcIds = ['metric-1', 'metric-7', 'metric-11', 'metric-20'];
  var lwcRendered = lwcIds.map(function(id) {
    var el = document.getElementById(id);
    return { id: id, hasCanvas: !!(el && el.querySelector('canvas')), hasChild: !!(el && el.firstChild) };
  });
  var noDataDivs = Array.from(document.querySelectorAll('div')).filter(function(d) {
    return d.textContent && d.textContent.trim() === 'No data available';
  });
  var canvasIds = ['metric-3', 'metric-4', 'metric-6', 'metric-8', 'metric-9', 'metric-10', 'metric-12', 'metric-13', 'metric-14', 'metric-15', 'metric-16', 'metric-17', 'metric-18', 'metric-19'];
  var chartjsWidths = canvasIds.map(function(id) {
    var el = document.getElementById(id);
    return { id: id, width: el ? el.offsetWidth : 0 };
  });
  return { lwcRendered: lwcRendered, noDataCount: noDataDivs.length, chartjsWidths: chartjsWidths };
}

